<table border="1"><thead><tr><th>Pegawai</th><th>Unit</th><th>Jenis Cuti</th><th>Tahun</th><th>Hak</th><th>Terpakai</th><th>Reserved</th><th>Sisa</th></tr></thead><tbody>@foreach($balances as $balance)<tr><td>{{ optional($balance->user)->name }}</td><td>{{ optional(optional($balance->user)->unit)->nama ?: '-' }}</td><td>{{ optional($balance->leaveType)->name }}</td><td>{{ $balance->year }}</td><td>{{ $balance->opening_balance + $balance->entitlement + $balance->carry_forward + $balance->adjustment_plus - $balance->adjustment_minus }}</td><td>{{ $balance->used_days }}</td><td>{{ $balance->reserved_days }}</td><td>{{ $balance->remaining_balance }}</td></tr>@endforeach</tbody></table>
